-- Cambodia geo gazetteer: provinces > districts > communes > villages.
-- Seeded from the official tbl_* datasets. Used to drive the cascading address
-- selects on Nokor profiles. Reference data — readable by any signed-in user,
-- writable only via migrations (service role bypasses RLS).

create table if not exists public.kh_provinces (
  code text primary key,
  name_km text not null,
  name_en text not null,
  type text
);

create table if not exists public.kh_districts (
  code text primary key,
  province_code text not null references public.kh_provinces (code),
  name_km text not null,
  name_en text not null,
  type text
);

create table if not exists public.kh_communes (
  code text primary key,
  district_code text not null references public.kh_districts (code),
  province_code text not null,
  name_km text not null,
  name_en text not null,
  type text
);

create table if not exists public.kh_villages (
  code text primary key,
  commune_code text not null references public.kh_communes (code),
  district_code text not null,
  province_code text not null,
  name_km text not null,
  name_en text not null,
  type text
);

create index if not exists kh_districts_province_idx on public.kh_districts (province_code);
create index if not exists kh_communes_district_idx on public.kh_communes (district_code);
create index if not exists kh_villages_commune_idx on public.kh_villages (commune_code);

alter table public.kh_provinces enable row level security;
alter table public.kh_districts enable row level security;
alter table public.kh_communes enable row level security;
alter table public.kh_villages enable row level security;

create policy "kh_provinces readable when signed in" on public.kh_provinces
  for select using (auth.uid() is not null);
create policy "kh_districts readable when signed in" on public.kh_districts
  for select using (auth.uid() is not null);
create policy "kh_communes readable when signed in" on public.kh_communes
  for select using (auth.uid() is not null);
create policy "kh_villages readable when signed in" on public.kh_villages
  for select using (auth.uid() is not null);

-- Structured address codes on profiles (both the current place and hometown).
-- current_city / hometown keep a denormalised display string for existing
-- readers (nearby RPC, chat lists); these codes re-select the dropdowns.
alter table public.profiles
  add column if not exists current_province_code text,
  add column if not exists current_district_code text,
  add column if not exists current_commune_code text,
  add column if not exists current_village_code text,
  add column if not exists home_province_code text,
  add column if not exists home_district_code text,
  add column if not exists home_commune_code text,
  add column if not exists home_village_code text;

